import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './ProblemList.css'; // You can use your existing styling

function ProblemList() {
  const [problems, setProblems] = useState([]);
  const [search, setSearch] = useState('');
  const [selectedProblem, setSelectedProblem] = useState(null);
  const [userAnswer, setUserAnswer] = useState('');
  const [feedback, setFeedback] = useState('');
  const [points, setPoints] = useState(0);
  const [showSolution, setShowSolution] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchProblems() {
      setLoading(true);
      try {
        const token = localStorage.getItem('token');
        const headers = token ? { Authorization: `Bearer ${token}` } : {};
        const res = await axios.get('http://localhost:5000/api/problems', { headers });
        setProblems(res.data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch problems.');
      } finally {
        setLoading(false);
      }
    }

    fetchProblems();
  }, []);

  const filteredProblems = problems.filter((p) =>
    p.title.toLowerCase().includes(search.toLowerCase())
  );

  const checkAnswer = () => {
    if (!selectedProblem) return;
  
    const normalize = (str) => {
      return str
        ?.toLowerCase()
        .replace(/[^0-9a-z.\-+/=]/gi, '') // keep basic math characters
        .replace(/^x=/, '') // remove 'x=' if present at start
        .trim();
    };
  
    const tryEvaluate = (input) => {
      try {
        // eslint-disable-next-line no-new-func
        return Function('"use strict";return (' + input + ')')();
      } catch {
        return null;
      }
    };
    const checkAnswer = () => {
      if (!selectedProblem) return;
    
      const normalize = (str) => {
        return str
          ?.toLowerCase()
          .replace(/[^0-9a-z.\-+/=]/gi, '') // keep basic math characters
          .replace(/^x=/, '') // remove 'x=' if present at start
          .trim();
      };
    
      const tryEvaluate = (input) => {
        try {
          // eslint-disable-next-line no-new-func
          return Function('"use strict";return (' + input + ')')();
        } catch {
          return null;
        }
      };
    
      const correctAnswer = selectedProblem.answer?.trim().toLowerCase();
      const user = userAnswer.trim().toLowerCase();
    
      console.log('Correct Answer:', correctAnswer);
      console.log('User Answer:', user);
    
      const extractNum = (str) => {
        const match = str?.match(/-?\d+(\.\d+)?/);
        return match ? parseFloat(match[0]) : null;
      };
    
      const correctNum = extractNum(correctAnswer);
      const userNum = extractNum(user);
    
      console.log('Extracted correctNum:', correctNum);
      console.log('Extracted userNum:', userNum);
    
      const matchByNumber = correctNum !== null && userNum !== null && correctNum === userNum;
      const matchByString = correctAnswer === user;
    
      console.log('matchByNumber:', matchByNumber);
      console.log('matchByString:', matchByString);
    
      const correctRaw = selectedProblem.answer || '';
    
      const correct = normalize(correctRaw);
      const correctVal = tryEvaluate(correct);
      const userVal = tryEvaluate(user);
    
      const stringMatch = correct === user;
      const numericMatch = correctVal !== null && userVal !== null && Math.abs(correctVal - userVal) < 0.0001;
    
      if (stringMatch || numericMatch) {
        let bonus = 0;
        if (selectedProblem.difficulty === 'Easy') bonus = 1;
        else if (selectedProblem.difficulty === 'Medium') bonus = 3;
        else if (selectedProblem.difficulty === 'Hard') bonus = 5;
    
        setPoints((prev) => prev + bonus);
        setFeedback(`✅ Correct! +${bonus} points`);
      } else {
        setFeedback('❌ Incorrect. Try again or check the solution.');
      }
    };
    
  

  if (loading) return <p>Loading problems...</p>;
  if (error) return <p style={{ color: 'red' }}>Error: {error}</p>;

  return (
    <>
      <div className="container">
        <h1>Math Problems</h1>
        <p className="points">🎯 Points: {points}</p>
        <button 
          onClick={() => {
            localStorage.removeItem('token');
            window.location.href = '/login';
          }}
        >
          Logout
        </button>
        <input
          type="text"
          placeholder="Search problems by title..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="search-input"
        />
        {filteredProblems.length === 0 ? (
          <p className="no-results">No math problems found.</p>
        ) : (
          <div className="problems-list">
            {filteredProblems.map((p) => (
              <div
                key={p._id}
                className="problem-card"
                onClick={() => {
                  setSelectedProblem(p);
                  setUserAnswer('');
                  setFeedback('');
                  setShowSolution(false);
                }}
              >
                {p.imageUrl && (
                  <img src={p.imageUrl} alt={p.title} className="problem-img" />
                )}
                <h3>{p.title} <span className="difficulty">({p.difficulty})</span></h3>
                <p dangerouslySetInnerHTML={{ __html: p.description }} />
              </div>
            ))}
          </div>
        )}
      </div>

      {selectedProblem && (
        <div className="modal-overlay" onClick={() => setSelectedProblem(null)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <h2>{selectedProblem.title}</h2>

            {selectedProblem.imageUrl && (
              <img src={selectedProblem.imageUrl} alt={selectedProblem.title} className="problem-img" />
            )}

            <p dangerouslySetInnerHTML={{ __html: selectedProblem.description }} />

            {!showSolution && (
              <>
                <textarea
                  className="answer-input"
                  placeholder="Type your answer here..."
                  value={userAnswer}
                  onChange={(e) => setUserAnswer(e.target.value)}
                  rows={3}
                />
                <div className="button-group">
                  <button className="check-answer-btn" onClick={checkAnswer}>Submit Answer</button>
                  <button className="show-solution-btn" onClick={() => setShowSolution(true)}>Show Solution</button>
                </div>
                {feedback && <div className="feedback">{feedback}</div>}
              </>
            )}

            {showSolution && (
              <>
                {feedback && <div className="feedback">{feedback}</div>}
                <div className="solution">
                  <strong>Solution:</strong>
                  <p>{selectedProblem.solution || 'No solution provided.'}</p>
                  {selectedProblem.solution && (
                    <>
                      <strong>Answer:</strong>
                      <p>{selectedProblem.solution}</p>
                    </>
                  )}
                </div>
                <button className="back-to-problem-btn" onClick={() => setShowSolution(false)}>Back to Problem</button>
              </>
            )}
          </div>
        </div>
      )}
    </>
  );
}
}
export default ProblemList;
